import{_ as a,o as l,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6290_良維/20260424/G11_前十大客戶與供應商穩定度_投資研究員.md","filePath":"審計報告庫/經營審計/6290_良維/20260424/G11_前十大客戶與供應商穩定度_投資研究員.md"}'),r={name:"審計報告庫/經營審計/6290_良維/20260424/G11_前十大客戶與供應商穩定度_投資研究員.md"};function t(n,e,c,s,d,p){return l(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="g11-前十大客戶與供應商穩定度-投資研究員-審計報告" tabindex="-1">G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告 <a class="header-anchor" href="#g11-前十大客戶與供應商穩定度-投資研究員-審計報告" aria-label="Permalink to &quot;G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>截至2025年全年最新公開數據，良維客戶集中度呈現「結構性集中但有序可控」。第一大客戶AWS佔營收比重約28-30%（2025年資料中心業務已提升至36%佔比），屬中度集中風險。但客戶結構正在從分散的消費電子轉向高成長的雲端服務供應商(CSP)，前五大客戶多為Tier-1世界級品牌（AWS、Apple、Dell、HP、Lenovo），客戶黏性極高且合作歷史超過15-20年。供應商端因原物料以銅材為主（市場化定價），供應鏈依賴單一廠商風險低。整體判定為警訊可控層級（未到高度風險）。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>評級：B（持平偏佳，集中度風險可控但需關注）</p><p><strong>數據基石</strong>：</p><ul><li>AWS為良維最大客戶，佔營收比重約28-30%</li><li>資料中心與伺服器業務佔比從2024年24%躍升至2025年前10月的36%</li><li>全球TV電源線市佔率40%，客戶基礎極其廣泛，非僅集中於單一產業</li><li>前十大客戶清單包含：AWS、Apple、Dell、HP、Lenovo、ChargePoint、Lucid、IBM、Cisco、Dyson等一線品牌</li><li>2025年毛利率達31.4%（2023年23.9%、2024年25.4%），毛利率持續改善驗證了客戶結構升級、議價力增強</li><li>國內競爭對手極少（僅1家台廠），國際大廠Amphenol在高靈活性方面不如良維</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1. 客戶集中度穿透分析</strong></p><p>良維近三年客戶結構發生質變：</p><ul><li><strong>2023年</strong>：消費電子及電腦週邊仍佔營收過半，資料中心佔比約20%</li><li><strong>2024年</strong>：AI伺服器需求爆發，資料中心佔比提升至24%，AWS成為第一大客戶（佔比約25%）</li><li><strong>2025年</strong>：資料中心及伺服器佔比大幅攀升至36%，加上電腦周邊設備45%，兩者合計達81%</li></ul><p>依公開資訊，AWS佔良維營收比重約28-30%（約新台幣28-30億元），且良維為AWS大電力電源線第一供應商，供貨佔AWS該品項的70%。此集中度在電源線產業中不算異常，因為Tier-1客戶通常要求產能優先分配。</p><p><strong>2. 供應鏈韌性審核</strong></p><p>良維對上游供應商依賴度極低。主要原物料為銅、塑料、連接器，均為全球大宗商品，供應來源多元化。良維具備垂直整合能力（90%以上銅線由自產供應），大幅降低外部供應依賴。年報中明確記載：「為降低生產成本，透過生產自動化及轉移量產地點至廣西憑祥，以降低人工成本。」以及「分散產地，降低中美貿易戰影響，擴大泰國廠生產規模。」</p><p><strong>3. 掉單壓力測試（Order-Loss Stress Test）</strong></p><p>模擬最壞情境：假設AWS訂單歸零（28%營收消失）：</p><ul><li>2025年營收約101.5億，AWS佔約28.4億</li><li>若AWS歸零，營收降至約73.1億，但固定費用約5億（營業費用中的固定部分）仍在</li><li>2025年營業利益約17.9億，若損失高毛利AWS訂單（毛利率估算約35%+），營業利益可能縮水至約5-8億</li><li>但考量其他CSP客戶（微軟、Google）訂單正在成長中，實際衝擊會小於此假設</li></ul><p>結論：短期衝擊顯著但公司生存無虞，且CSP客戶已多元化布局中。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>良維的客戶集中度風險有兩面性。負面看，單一客戶AWS佔比近30%，存在訂單波動風險；但是從正面看，AWS是CSP中資本支出最積極的業者之一（2025-2030年資料中心基礎建設年複合成長率估38%），且良維在該客戶的供應份額已達70%，短期被取代的機率極低。</p><p>更關鍵的是，公司正在將客戶基礎從消費電子轉向伺服器/CSP，每一家新增的CSP客戶都代表著新的營收支柱。法說會已揭露與微軟、Google均有不同程度的合作（量產中/送樣中/洽談中），多元化正在發生。</p><p>供應商端的可控性遠優於客戶端。良維的銅線自主供應比例高，且銅價波動對高毛利的大電流產品影響小（法說會明確指出「大電流產品中，銅佔成本比例相當低」）。</p><p>最大風險並非「掉單」，而是「佔比過高使市場容易放大恐懼」。當AWS資本支出放緩時，良維股價可能先於EPS受衝擊。這是一個必須接受的Beta風險。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: revenue 6290 2023-01-01 ~ 2026-04-24 (月營收數據，涵蓋2023-2026年)</li><li><code>數據採集器查詢</code>: finance 6290 2023-01-01 ~ 2026-04-24 (綜合損益表，毛利率/營業利益率趨勢)</li><li><code>數據採集器查詢</code>: cash_flow 6290 2023-01-01 ~ 2026-04-24 (現金流量表，CapEx與營運現金流)</li><li><code>Web Search - 工商時報</code>: 良維供應AWS大電力電源線，單一客戶占營收比重近30%</li><li><code>Web Search - 經濟日報 2026法說報導</code>: 良維與主要CSP都有專案進行，資料中心佔比36%</li><li><code>Web Search - 富果法說備忘錄 20251211</code>: 詳細的客戶結構、產品組合與競爭分析</li><li><code>Web Search - 良維113年報 (致股東報告書)</code>: 完整客戶名單包括Apple、HPI、Dell、Lenovo、AWS、IBM、Cisco、HPE、Lucid、ChargePoint等；以及安規護城河描述</li><li><code>Web Search - MoneyDJ</code>: AWS佔良維營收近30%，良維佔AWS大電力線供應比重七成</li></ul>',27)])])}const S=a(r,[["render",t]]);export{h as __pageData,S as default};
